import React, { useState, useEffect } from 'react';
import './styles/Header.css';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { handleLogout, getCurrentUser } from '../Pages/Auth/Logout';  // ← هنا التعديل

export default function Header() {
  const location = useLocation();
  const navigate = useNavigate();

  const [user, setUser] = useState(null);

  // جلب بيانات المستخدم
  useEffect(() => {
    const userData = getCurrentUser();
    setUser(userData);
  }, [location]);

  // دالة تسجيل الخروج
  function logout() {
    handleLogout(navigate);
  }

  return (
    <header className="header">
      <div className="container">
        <div className="logo">
          <Link to="/">
            <h2>المنصة التعليمية</h2>
          </Link>
        </div>
        
        <nav className="nav">
          <Link 
            to="/" 
            className={location.pathname === '/' ? 'active' : ''}
          >
            الرئيسية
          </Link>
          
          <Link 
            to="/courses" 
            className={location.pathname === '/courses' ? 'active' : ''}
          >
            الكورسات
          </Link>
          
          <Link 
            to="/pricing" 
            className={location.pathname === '/pricing' ? 'active' : ''}
          >
            الأسعار
          </Link>

          {user ? (
            <>
              <span className="user-name">مرحباً، {user.name}</span>
              
              {user.role === 'admin' && (
                <Link 
                  to="/dashboard" 
                  className={location.pathname === '/dashboard' ? 'active' : ''}
                >
                  لوحة التحكم
                </Link>
              )}
              
              <button onClick={logout} className="logout-btn">
                تسجيل الخروج
              </button>
            </>
          ) : (
            <>
              <Link 
                to="/login" 
                className={`login-btn ${location.pathname === '/login' ? 'active' : ''}`}
              >
                تسجيل الدخول
              </Link>
              
              <Link 
                to="/register" 
                className={`register-btn ${location.pathname === '/register' ? 'active' : ''}`}
              >
                إنشاء حساب
              </Link>
            </>
          )}
        </nav>
      </div>
    </header>
  );
}
